const input = $input.first().json;
const action = input.action || 'VALIDATE';
const dispatch = input.dispatch || {};
const inventory = input.inventory || [];
const tolerance = Number(dispatch.weightTolerancePercent || 1.5);
const exceptions = [];

function releasedAvailable(productCode) {
  return inventory
    .filter((batch) => batch.productCode === productCode && batch.qualityStatus === 'RELEASED')
    .reduce((sum, batch) => sum + Math.max(Number(batch.onHandQty || 0) - Number(batch.reservedQty || 0), 0), 0);
}

if (action === 'VALIDATE' || action === 'APPROVE_AND_RESERVE') {
  for (const line of dispatch.lines || []) {
    const available = releasedAvailable(line.productCode);
    if (available < Number(line.requestedQty || 0)) {
      exceptions.push({
        code: 'INSUFFICIENT_RELEASED_STOCK',
        message: `${line.productName || line.productCode} has ${available} released ${line.unit}, requested ${line.requestedQty}.`,
        controlStatus: 'BLOCKED'
      });
    }
  }
}

if (action === 'VERIFY_WEIGHT' && dispatch.expectedWeightKg) {
  const expected = Number(dispatch.expectedWeightKg);
  const actual = Number(dispatch.actualWeightKg || 0);
  const variance = Math.abs(((actual - expected) / expected) * 100);
  if (variance > tolerance) {
    exceptions.push({
      code: 'WEIGHT_VARIANCE_EXCEEDED',
      message: `Actual weight variance is ${variance.toFixed(2)}%, above ${tolerance}%.`,
      controlStatus: 'BLOCKED'
    });
  }
}

if (action === 'VERIFY_DOCUMENTS') {
  const missing = (dispatch.documents || []).filter((doc) => !doc.present);
  for (const doc of missing) {
    exceptions.push({
      code: 'MISSING_DOCUMENT',
      message: `${doc.type} is missing.`,
      controlStatus: 'BLOCKED'
    });
  }
}

return [{
  json: {
    ok: exceptions.length === 0,
    action,
    controlStatus: exceptions.length ? 'BLOCKED' : 'CLEAR',
    exceptions,
    recommendedNextStatus: exceptions.length ? dispatch.status : input.nextStatus || null,
    auditedAt: new Date().toISOString()
  }
}];
